<?php
namespace App\Http\Controllers;use App\Models\User;use App\Services\WalletService;use Illuminate\Http\Request;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\Hash;class AuthController extends Controller{public function loginForm(){return view('auth.login');}public function registerForm(){return view('auth.register');}public function login(Request $request){$data=$request->validate(['email'=>'required|email','password'=>'required']);if(Auth::attempt($data)){$request->session()->regenerate();return redirect('/')->with('success','Login successful.');}return back()->withInput()->with('error','Invalid email or password.');}public function register(Request $request,WalletService $wallet){$data=$request->validate(['name'=>'required|max:191','email'=>'required|email|max:191|unique:users,email','password'=>'required|min:6|confirmed']);$user=User::create(['name'=>$data['name'],'email'=>$data['email'],'password'=>Hash::make($data['password']),'role'=>'user','status'=>1]);$wallet->ensure($user->id);Auth::login($user);return redirect('/')->with('success','Account created successfully.');}public function logout(Request $request){Auth::logout();$request->session()->invalidate();$request->session()->regenerateToken();return redirect('/login')->with('success','Logout successful.');}}
